```class Solution {
    public List<String> removeSubfolders(String[] folder) {
        Arrays.sort(folder);
        List<String> result = new ArrayList<>();
        for (String f : folder) {
            if (result.isEmpty() || !result.get(result.size() - 1).endsWith(f.substring(1))) {
                result.add(f);
            }
        }
        return result;
    }
}```
